const jwt = require('jsonwebtoken');

const config = {
  secret: 'shhhh', // The token is signed with this key. Don't share it!
}

function authenticationMiddleware(req, res, next) {
    const authHeader = req.headers['authorization'];

    if (authHeader !== undefined && authHeader.startsWith('Bearer ')) {
        const token = authHeader.split(' ')[1];

        try {
            // Verify the token and extract user information from it.
            let decodedToken = jwt.verify(token, config.secret);

            req.user = {
                email: decodedToken.email,
                isAdmin: decodedToken.isAdmin
            }
        } catch (error) {
            res.status(401).json({ message: 'Invalid token' });
            return; // Don't call next() if we're throwing an error.
        }
    }

    next();
}

